package com.crapi.filter;

import com.bucket4j.Bandwidth;
import com.bucket4j.Bucket;
import com.bucket4j.Refill;
import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import java.io.IOException;
import java.time.Duration;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;

@Component
public class OtpRateLimitFilter extends OncePerRequestFilter {

  private final Map<String, Bucket> buckets = new ConcurrentHashMap<>();

  @Override
  protected void doFilterInternal(
      HttpServletRequest req, HttpServletResponse res, FilterChain chain)
      throws ServletException, IOException {
    if (req.getRequestURI().contains("/check-otp")) {
      String key = req.getRemoteAddr();
      Bucket bucket =
          buckets.computeIfAbsent(
              key,
              k ->
                  Bucket.builder()
                      .addLimit(
                          Bandwidth.classic(5, Refill.intervally(5, Duration.ofMinutes(10))))
                      .build());
      if (!bucket.tryConsume(1)) {
        res.setStatus(429);
        res.setContentType("application/json");
        res.getWriter()
            .write(
                "{\"message\":\"Too many OTP attempts. Please wait 10 minutes.\",\"status\":429}");
        return;
      }
    }
    chain.doFilter(req, res);
  }
}

